3_real_world_example.code:
class ApiService {
  // Complex internal logic hidden from the user
  #getAuthToken() { return 'Bearer abc123XYZ'; }
  #formatHeaders() { return { Authorization: this.#getAuthToken() }; }
  #parseJSON(response) { return response.json(); }

  // The simple, Abstracted interface exposed to the user
  async fetchUserData() {
    const headers = this.#formatHeaders();
    const res = await fetch('/api/user', { headers });
    return this.#parseJSON(res);
  }
}

const api = new ApiService();
// The user just calls one simple method. They don't care about tokens or headers!
api.fetchUserData().then(console.log);

